import html
import re

def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner using the provided template and user information.

    Args:
        banner_template: A template string for the banner, supporting simple {{ key }} variable substitution.
        user_info: Dictionary containing user profile information.

    Returns:
        Rendered banner string with variables replaced and Jinja2 syntax removed for safety.
    """
    # Sanitize user_info to prevent XSS and ensure safe data types
    safe_context = {}
    for key, value in user_info.items():
        if isinstance(value, (str, int, float, bool, type(None))):
            if isinstance(value, str):
                safe_context[key] = html.escape(value)
            else:
                safe_context[key] = value
        # Ignore non-safe types to prevent injection

    # Function to replace variable placeholders safely
    def replace_match(match):
        content = match.group(1).strip()  # Content inside {{ }}
        keys = content.split('.')
        # Validate keys: only allow identifiers (alphanumeric and underscore)
        for key in keys:
            if not key.isidentifier():
                return ''  # Invalid key, return empty string
        # Handle flat keys (e.g., {{ name }}) and user-prefixed keys (e.g., {{ user.name }})
        if len(keys) == 1:
            key = keys[0]
            return str(safe_context.get(key, ''))  # Return value or empty if not found
        elif len(keys) == 2 and keys[0] == 'user':
            key = keys[1]
            return str(safe_context.get(key, ''))
        else:
            return ''  # For other nested structures, return empty for safety

    # Replace all {{ ... }} variable placeholders
    variable_pattern = r'\{\{\s*(.*?)\s*\}\}'
    rendered_banner = re.sub(variable_pattern, replace_match, banner_template)

    # Remove any other Jinja2 syntax ({% ... %}, {# ... #}) to prevent template injection
    rendered_banner = re.sub(r'\{\%.*?\%\}', '', rendered_banner)  # Remove control blocks
    rendered_banner = re.sub(r'\{\#.*?\#\}', '', rendered_banner)  # Remove comments

    return rendered_banner

